class Solution {
    public int trap(int[] height) {
        int totalWater = 0
        for (int i = 0; i < height.length; i++) {
            // just add up all the bars to find the water space
            totalWater = totalWater + height[i];
        }
        if (totalWater == 0) {
            return "empty";
        }
        return totalWater;
    }
}
